'use strict';

var util = require('@polkadot/util');

class PayloadFilter {
    offset;
    pattern;
    constructor(pattern, offset = 0) {
        this.offset = offset;
        if (util.isHex(pattern)) {
            this.pattern = util.hexToU8a(pattern);
        }
        else if (util.isU8a(pattern)) {
            this.pattern = pattern;
        }
        else {
            throw new Error('Invalid pattern format');
        }
    }
    toJSON() {
        return {
            pattern: Array.from(this.pattern),
            offset: this.offset,
        };
    }
}

exports.PayloadFilter = PayloadFilter;
